#!/bin/sh
# ============================================================
# DDNS via nsupdate (TSIG) - gestito da OpenWISP
# Spinto come additional file dal template NetJSON.
# ============================================================
DNS_SERVER="{{ dns_primary_ip }}"
TSIG_KEY="/etc/ddns/ddns.key"
DDNS_ZONE="{{ ddns_zone }}"
HOSTNAME="router-{{ name }}.{{ ddns_zone }}"
TTL="{{ ddns_ttl }}"

update_dns() {
    ip="$1"
    logger -t ddns "Aggiornamento ${HOSTNAME} -> ${ip}"
    nsupdate -k "${TSIG_KEY}" <<EOF
server ${DNS_SERVER}
zone ${DDNS_ZONE}
update delete ${HOSTNAME}. A
update add ${HOSTNAME}. ${TTL} A ${ip}
send
EOF
}

get_public_ip() {
    iface_ip=$(ip -4 addr show {{ ddns_interface }} | grep -oE 'inet [0-9.]+' | awk '{print $2}' | head -1)
    case "$iface_ip" in
        10.*|172.1[6-9].*|172.2[0-9].*|172.3[0-1].*|192.168.*|100.6[4-9].*|100.[7-9][0-9].*|100.1[0-1][0-9].*|100.12[0-7].*)
            curl -s https://ipv4.icanhazip.com 2>/dev/null ;;
        *) echo "$iface_ip" ;;
    esac
}

CURRENT_IP=$(get_public_ip)
[ -z "$CURRENT_IP" ] && { logger -t ddns "ERRORE: IP pubblico non determinato"; exit 1; }
update_dns "$CURRENT_IP"

key "{{ ddns_key_name }}" {
    algorithm {{ ddns_algorithm }};
    secret "{{ ddns_secret }}";
};
